class Solution {
public:
    int findTheLongestSubstring(string s) {
        int maxLen = 0;
        int vowelState = 0;
        unordered_map<int, int> seen;

        seen[0] = -1;

        for (int i = 0; i < s.size(); ++i) {
            switch (s[i]) {
                case 'a': vowelState ^= 1 << 0; break;
                case 'e': vowelState ^= 1 << 1; break;
                case 'i': vowelState ^= 1 << 2; break;
                case 'o': vowelState ^= 1 << 3; break;
                case 'u': vowelState ^= 1 << 4; break;
            }

            if (seen.find(vowelState) == seen.end()) {
                seen[vowelState] = i;
            } else {
                maxLen = max(maxLen, i - seen[vowelState]);
            }
        }

        return maxLen;
    }
};
